  1→import {
  2→  type ReactNode,
  3→  useCallback,
  4→  useEffect,
  5→  useRef,
  6→  useState,
  7→} from 'react';
  8→import './actions_dropdown.scss';
  9→
 10→export interface DropdownAction {
 11→  label: string;
 12→  shortcut?: ReactNode;
 13→  onClick?: () => void;
 14→}
 15→
 16→interface ActionsDropdownProps {
 17→  actions: DropdownAction[];
 18→  open: boolean;
 19→  onClose: () => void;
 20→}
 21→
 22→export function ActionsDropdown({
 23→  actions,
 24→  open,
 25→  onClose,
 26→}: ActionsDropdownProps) {
 27→  const [activeIndex, setActiveIndex] = useState(0);
 28→  const dropdownRef = useRef<HTMLDivElement>(null);
 29→
 30→  useEffect(() => {
 31→    if (open) {
 32→      setActiveIndex(0);
 33→    }
 34→  }, [open]);
 35→
 36→  const executeAction = useCallback(
 37→    (index: number) => {
 38→      actions[index]?.onClick?.();
 39→      onClose();
 40→    },
 41→    [
 42→      actions,
 43→      onClose,
 44→    ],
 45→  );
 46→
 47→  useEffect(() => {
 48→    if (!open) return;
 49→
 50→    function handleKeyDown(e: KeyboardEvent) {
 51→      if (e.key === 'Escape') {
 52→        e.preventDefault();
 53→        e.stopPropagation();
 54→        onClose();
 55→        return;
 56→      }
 57→
 58→      if (e.key === 'ArrowDown') {
 59→        e.preventDefault();
 60→        e.stopPropagation();
 61→        setActiveIndex(i => (i < actions.length - 1 ? i + 1 : 0));
 62→        return;
 63→      }
 64→
 65→      if (e.key === 'ArrowUp') {
 66→        e.preventDefault();
 67→        e.stopPropagation();
 68→        setActiveIndex(i => (i > 0 ? i - 1 : actions.length - 1));
 69→        return;
 70→      }
 71→
 72→      if (e.key === 'Enter') {
 73→        e.preventDefault();
 74→        e.stopPropagation();
 75→        executeAction(activeIndex);
 76→      }
 77→    }
 78→
 79→    window.addEventListener('keydown', handleKeyDown, true);
 80→    return () => window.removeEventListener('keydown', handleKeyDown, true);
 81→  }, [
 82→    open,
 83→    actions.length,
 84→    activeIndex,
 85→    onClose,
 86→    executeAction,
 87→  ]);
 88→
 89→  useEffect(() => {
 90→    if (!open) return;
 91→
 92→    function handleClickOutside(e: MouseEvent) {
 93→      if (
 94→        dropdownRef.current &&
 95→        !dropdownRef.current.contains(e.target as Node)
 96→      ) {
 97→        onClose();
 98→      }
 99→    }
100→
101→    document.addEventListener('mousedown', handleClickOutside);
102→    return () => document.removeEventListener('mousedown', handleClickOutside);
103→  }, [
104→    open,
105→    onClose,
106→  ]);
107→
108→  useEffect(() => {
109→    if (!open) return;
110→    const container = dropdownRef.current;
111→    if (!container) return;
112→
113→    const activeElement = container.querySelector<HTMLElement>(
114→      `[data-dropdown-index="${activeIndex}"]`,
115→    );
116→    activeElement?.scrollIntoView({ block: 'nearest' });
117→  }, [
118→    open,
119→    activeIndex,
120→  ]);
121→
122→  if (!open) return null;
123→
124→  return (
125→    <div className="actions-dropdown" ref={dropdownRef} role="menu">
126→      {actions.map((action, index) => (
127→        <button
128→          key={action.label}
129→          className={`actions-dropdown__item${index === activeIndex ? ' actions-dropdown__item--active' : ''}`}
130→          data-dropdown-index={index}
131→          role="menuitem"
132→          type="button"
133→          onClick={() => executeAction(index)}
134→          onMouseEnter={() => setActiveIndex(index)}
135→        >
136→          <span className="actions-dropdown__label">{action.label}</span>
137→          {action.shortcut && (
138→            <span className="actions-dropdown__shortcut">
139→              {action.shortcut}
140→            </span>
141→          )}
142→        </button>
143→      ))}
144→    </div>
145→  );
146→}
