 5→export interface Action {
 6→  label: string;
 7→  shortcut: ReactNode;
 8→  onClick?: () => void;
 9→}
10→
11→export interface ActionPanelProps {
12→  actions: Action[];
13→  dropdownOpen: boolean;
14→  dropdownActions: DropdownAction[];
15→  onDropdownClose: () => void;
16→}
