18→export function ActionPanel({
19→  actions,
20→  dropdownOpen,
21→  dropdownActions,
22→  onDropdownClose,
23→}: ActionPanelProps) {
24→  const primary = actions[0];
25→  if (!primary) return null;
26→
27→  const secondary = actions.slice(1);
28→
29→  return (
30→    <footer className="action-panel" role="toolbar" aria-label="Actions">
