35→          type="button"
36→        >
37→          <span className="action-panel__label">{primary.label}</span>
38→          <span className="action-panel__shortcut">{primary.shortcut}</span>
39→        </button>
40→      </div>
41→      {secondary.length > 0 && (
42→        <div className="action-panel__secondary">
43→          {secondary.map(action => (
44→            <button
45→              key={action.label}
46→              className="action-panel__action"
47→              onClick={action.onClick}
48→              type="button"
49→            >
50→              <span className="action-panel__label">{action.label}</span>
51→              <span className="action-panel__shortcut">{action.shortcut}</span>
52→            </button>
53→          ))}
54→        </div>
