 91→export function App() {
 92→  const [query, setQuery] = useState('');
 93→  const [selectedIndex, setSelectedIndex] = useState(0);
 94→  const [actionsOpen, setActionsOpen] = useState(false);
 95→
 96→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
 97→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
 98→  const selectedItem = allItems[selectedIndex];
 99→
100→  const handleQueryChange = useCallback((value: string) => {
101→    setQuery(value);
102→    setSelectedIndex(0);
103→    setActionsOpen(false);
104→  }, []);
105→
106→  const handleActiveIndexChange = useCallback((index: number) => {
107→    setSelectedIndex(index);
108→    setActionsOpen(false);
109→  }, []);
110→
111→  const toggleActions = useCallback(() => {
112→    setActionsOpen(prev => !prev);
113→  }, []);
114→
115→  const closeActions = useCallback(() => {
116→    setActionsOpen(false);
117→  }, []);
118→
119→  useEffect(() => {
120→    function handleKeyDown(e: KeyboardEvent) {
121→      if (e.key === 'k' && e.metaKey) {
122→        e.preventDefault();
123→        setActionsOpen(prev => !prev);
124→      }
125→    }
126→
127→    window.addEventListener('keydown', handleKeyDown);
128→    return () => window.removeEventListener('keydown', handleKeyDown);
129→  }, []);
130→
131→  const detail = selectedItem?.detail;
132→
133→  const dropdownActions = useMemo(
134→    () => [
135→      {
136→        label: 'Open',
137→        shortcut: <Kbd keys={['↵']} />,
138→      },
139→      {
140→        label: 'Copy Name',
141→        shortcut: (
142→          <Kbd
143→            keys={[
144→              '⌘',
145→              'C',
146→            ]}
147→          />
148→        ),
149→      },
150→      {
151→        label: 'Show Detail',
152→        shortcut: (
153→          <Kbd
154→            keys={[
155→              '⌘',
156→              'D',
157→            ]}
158→          />
159→        ),
160→      },
161→      {
162→        label: 'Pin to Top',
163→        shortcut: (
164→          <Kbd
165→            keys={[
166→              '⌘',
167→              'P',
168→            ]}
169→          />
170→        ),
171→      },
172→    ],
173→    [],
174→  );
175→
176→  return (
177→    <CommandPalette>
178→      <SearchBar
179→        value={query}
180→        onChange={handleQueryChange}
181→        activeDescendantId={
182→          allItems.length > 0 ? `list-item-${selectedIndex}` : undefined
183→        }
184→      />
185→      <div
186→        className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
187→      >
188→        <div className="command-palette__list-container">
189→          {allItems.length === 0 ? (
190→            <EmptyState
191→              icon={<SearchIcon />}
192→              title="No Results"
193→              description="Try a different search term"
194→            />
195→          ) : (
196→            <List
197→              itemCount={allItems.length}
198→              onActiveIndexChange={handleActiveIndexChange}
199→            >
200→              {(() => {
201→                let globalIndex = 0;
202→                return filtered.map(section => (
203→                  <ListSection key={section.title} title={section.title}>
204→                    {section.items.map(item => {
205→                      const idx = globalIndex++;
206→                      return (
207→                        <ListItem
208→                          key={item.id}
209→                          index={idx}
210→                          title={item.title}
211→                          subtitle={item.subtitle}
212→                          icon={item.icon}
213→                          accessories={item.accessories}
214→                        />
215→                      );
216→                    })}
217→                  </ListSection>
218→                ));
219→              })()}
220→            </List>
221→          )}
222→        </div>
223→        {detail && (
224→          <Detail
225→            markdown={detail.markdown}
226→            metadata={
227→              detail.metadata ? (
228→                <DetailMetadata>
229→                  {detail.metadata.map(renderMetadataEntry)}
230→                </DetailMetadata>
231→              ) : undefined
232→            }
233→          />
234→        )}
235→      </div>
236→      <ActionPanel
237→        actions={[
238→          {
239→            label: 'Open',
240→            shortcut: <Kbd keys={['↵']} />,
241→          },
242→          {
243→            label: 'Actions',
244→            shortcut: (
245→              <Kbd
246→                keys={[
247→                  '⌘',
248→                  'K',
249→                ]}
250→              />
251→            ),
252→            onClick: toggleActions,
253→          },
254→        ]}
255→        dropdownOpen={actionsOpen}
256→        dropdownActions={dropdownActions}
257→        onDropdownClose={closeActions}
258→      />
259→    </CommandPalette>
260→  );
261→}
